import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/updating-fabric.1C0PZ95m.js";const a=JSON.parse(`{"title":"Fabric updaten","description":"Een stap voor stap instructie voor het updaten van fabric.","frontmatter":{"title":"Fabric updaten","description":"Een stap voor stap instructie voor het updaten van fabric.","authors":["IMB11","modmuss50"],"files":[]},"headers":[],"relativePath":"1.21.1/translated/nl_nl/players/updating-fabric.md","filePath":"versions/1.21.1/translated/nl_nl/players/updating-fabric.md","lastUpdated":1761424914000}`);var o={name:`1.21.1/translated/nl_nl/players/updating-fabric.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Fabric updaten <a class="header-anchor" href="#h1" aria-label="Permalink to “Fabric updaten”">​</a></h1><p>Deze gids begeleidt u bij het updaten van Fabric voor de Minecraft Launcher.</p><p>Voor externe launchers dient u hun documentatie te raadplegen.</p><p>Het updaten van Fabric lijkt sterk op het installeren van Fabric, dus delen van deze handleiding zullen hetzelfde zijn als de handleiding <a href="./installing-fabric">Installing Fabric</a>.</p><h2 id="why-should-i-update-fabric-loader" tabindex="-1">Waarom Zou Ik Fabric Updaten? <a class="header-anchor" href="#why-should-i-update-fabric-loader" aria-label="Permalink to “Waarom Zou Ik Fabric Updaten?”">​</a></h2><p>Nieuwere mods hebben misschien een nieuwere versie van de Fabric Loader nodig om te werken, het is dus belangerijk om het up to date te houden om ervoor te zorgen dat je de nieuwste mods kan gebruiken.</p><p>Om Fabric te updaten, moet je ervoor zorgen dat de spel versie en Fabric Loader versie correct is, en dat op <code>Install</code> te klikken.</p><div class="warning custom-block"><p class="custom-block-title">BELANGRIJK</p><p>Zorg ervoor dat je &#39;Create Profile&#39; niet aanvinkt wanneer je de Installer gebruikt, anders maakt het een nieuw profiel aan, dat wij in dit geval niet nodig hebben.</p></div><h2 id="3-open-the-profile-in-the-minecraft-launcher" tabindex="-1">3. Open het Profiel in de Minecraft Launcher <a class="header-anchor" href="#3-open-the-profile-in-the-minecraft-launcher" aria-label="Permalink to “3. Open het Profiel in de Minecraft Launcher”">​</a></h2><p>Wanneer de installer klaar is, kan je de Minecraft launcher openen en naar de <code>installaties</code> tab gaan. Je moet naar je Fabrc Profile gaan en dat het edit scherm openen.</p><p>Vervan de oude versie met de nieuwste versie van de Fabric Loader die je net heb geinstalleerd en klik op <code>Save</code>.</p><p><img src="/assets/players/updating-fabric.png" alt="Fabric updaten in de Minecraft Launcher" loading="lazy"></p><h2 id="4-you-re-done" tabindex="-1">4. Je bent klaar! <a class="header-anchor" href="#4-you-re-done" aria-label="Permalink to “4. Je bent klaar!”">​</a></h2><p>Wanneer je de stappen hebt voltooid, kan je terug gaan naar het <code>Spelen</code> tab, selecteer het Fabric profiel van het menu in de onderste linker hoek en klik op speel!</p><p>Als je problemen tegenkomt terwijl je deze gids volgt, dan kan je voor hulp vragen in de <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> in het <code>#player-support</code> kanaal.</p>`,15)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};